package bench

import (
	"fmt"
	"os"
	"strings"
	"testing"
)

// corpusPath is the JSONL corpus generated by cmd/corpus-builder.
const corpusPath = "testdata/git_history_cases.jsonl"

// embeddingsPath is the pre-computed Gemini embeddings generated by cmd/embed-corpus.
const embeddingsPath = "testdata/git_history_embeddings.jsonl"

// TestGitHistoryCorpus runs the baseline and Ensō models over the full git
// history corpus and reports precision@1 for each.
//
// Run with -v to see per-model failure details:
//
//	go test ./internal/bench/ -run TestGitHistoryCorpus -v
func TestGitHistoryCorpus(t *testing.T) {
	if _, err := os.Stat(corpusPath); os.IsNotExist(err) {
		t.Skipf("corpus not found at %s — run cmd/corpus-builder first", corpusPath)
	}

	records, err := LoadGitHistoryRecords(corpusPath)
	if err != nil {
		t.Fatalf("load records: %v", err)
	}
	if len(records) == 0 {
		t.Fatal("corpus is empty")
	}

	cases, err := GitHistoryCases(records)
	if err != nil {
		t.Fatalf("build cases: %v", err)
	}
	t.Logf("corpus: %d records → %d valid cases", len(records), len(cases))

	// Load optional semantic model (requires pre-computed embeddings).
	semantic, err := LoadSemanticModel(embeddingsPath)
	if err != nil {
		t.Fatalf("load semantic model: %v", err)
	}
	if semantic == nil {
		t.Logf("no embeddings at %s — skipping semantic column (run cmd/embed-corpus)", embeddingsPath)
	}

	models := []Model{
		BaselineModel{},
		EnsoModel{},
	}
	results := make([]Result, len(models))
	for i, m := range models {
		results[i] = Run(m, cases)
	}

	// Score the semantic model separately (it's a QueryModel, not a Model).
	var semanticResult *Result
	if semantic != nil {
		r := RunQueryAware(semantic, cases)
		semanticResult = &r
	}

	// Print comparison table.
	t.Logf("\n%-35s  %5s  %5s", "Model", "P@1", "Score")
	t.Logf("%-35s  %5s  %5s", strings.Repeat("-", 35), "-----", "-----")
	for _, r := range results {
		t.Logf("%-35s  %d/%d  %.2f", r.Model, r.TopHits, r.Total, r.Score())
	}
	if semanticResult != nil {
		r := semanticResult
		t.Logf("%-35s  %d/%d  %.2f", r.Model, r.TopHits, r.Total, r.Score())
	}

	// Show what each model got wrong (verbose only).
	allResults := results
	if semanticResult != nil {
		allResults = append(allResults, *semanticResult)
	}
	for _, r := range allResults {
		if len(r.Failures) > 0 && testing.Verbose() {
			t.Logf("\n%s failures (%d):", r.Model, len(r.Failures))
			for _, name := range r.Failures {
				t.Logf("  FAIL %s", name)
			}
		}
	}

	// Regression guard: Ensō must not score below baseline on this corpus.
	baseScore := results[0].Score()
	ensoScore := results[1].Score()
	if ensoScore < baseScore {
		t.Errorf("Ensō (%.2f) scored below baseline (%.2f) — supersession regression",
			ensoScore, baseScore)
	}
}

// TestGitHistoryCorpusSummary prints a compact one-line summary. Useful for
// quick CI checks where -v is not set.
func TestGitHistoryCorpusSummary(t *testing.T) {
	if _, err := os.Stat(corpusPath); os.IsNotExist(err) {
		t.Skipf("corpus not found at %s — run cmd/corpus-builder first", corpusPath)
	}

	records, err := LoadGitHistoryRecords(corpusPath)
	if err != nil {
		t.Fatalf("load records: %v", err)
	}
	cases, err := GitHistoryCases(records)
	if err != nil {
		t.Fatalf("build cases: %v", err)
	}

	baseline := Run(BaselineModel{}, cases)
	enso := Run(EnsoModel{}, cases)

	sumParts := fmt.Sprintf("git-history n=%d | baseline=%.2f | enso=%.2f",
		len(cases), baseline.Score(), enso.Score())

	semantic, err := LoadSemanticModel(embeddingsPath)
	if err != nil {
		t.Fatalf("load semantic model: %v", err)
	}
	if semantic != nil {
		sr := RunQueryAware(semantic, cases)
		sumParts += fmt.Sprintf(" | semantic=%.2f", sr.Score())
	}

	t.Log(sumParts)
	if enso.Score() < baseline.Score() {
		t.Errorf("Ensō regression: %s", sumParts)
	}
}
